// ShareReceiverActivity.kt
package com.example.sharereceiver

import android.content.Intent
import android.net.Uri
import android.os.Bundle
import android.widget.ImageView
import android.widget.TextView
import androidx.appcompat.app.AppCompatActivity

class ShareReceiverActivity : AppCompatActivity() {

    private lateinit var sharedContentTextView: TextView
    private lateinit var sharedImageView: ImageView
    private lateinit var subjectTextView: TextView

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)
        setContentView(R.layout.activity_share_receiver)

        sharedContentTextView = findViewById(R.id.sharedContentTextView)
        sharedImageView = findViewById(R.id.sharedImageView)
        subjectTextView = findViewById(R.id.subjectTextView)

        handleIntent()
    }

    override fun onNewIntent(intent: Intent?) {
        super.onNewIntent(intent)
        setIntent(intent) // Update the activity's intent
        handleIntent() // Process the new intent
    }

    private fun handleIntent() {
        // Clear previous content
        sharedContentTextView.text = ""
        sharedImageView.setImageDrawable(null)
        subjectTextView.text = ""

        when (intent?.action) {
            Intent.ACTION_SEND -> {
                if ("text/plain" == intent.type) {
                    handleSendText(intent) // Handle text (URLs often come as text/plain)
                } else if (intent.type?.startsWith("image/") == true) {
                    handleSendImage(intent) // Handle image
                } else {
                    sharedContentTextView.text = "Unsupported content type: ${intent.type}"
                }
            }
            // For handling multiple items, uncomment and implement ACTION_SEND_MULTIPLE
            // Intent.ACTION_SEND_MULTIPLE -> {
            //     if (intent.type?.startsWith("image/") == true) {
            //         handleSendMultipleImages(intent)
            //     }
            // }
            else -> {
                sharedContentTextView.text = "No shared content received or unknown action."
            }
        }
    }

    private fun handleSendText(intent: Intent) {
        intent.getStringExtra(Intent.EXTRA_TEXT)?.let { sharedText ->
            sharedContentTextView.text = "Shared Text/URL:\n$sharedText"
        }
        intent.getStringExtra(Intent.EXTRA_SUBJECT)?.let { subject ->
            subjectTextView.text = "Subject:\n$subject"
        }
    }

    private fun handleSendImage(intent: Intent) {
        (intent.getParcelableExtra<Uri>(Intent.EXTRA_STREAM))?.let { imageUri ->
            sharedImageView.setImageURI(imageUri)
            sharedContentTextView.text = "Shared Image URI:\n$imageUri"
        }
        intent.getStringExtra(Intent.EXTRA_SUBJECT)?.let { subject ->
            subjectTextView.text = "Subject:\n$subject"
        }
    }

    // Example for handling multiple images if ACTION_SEND_MULTIPLE is added
    // private fun handleSendMultipleImages(intent: Intent) {
    //     val imageUris = intent.getParcelableArrayListExtra<Uri>(Intent.EXTRA_STREAM)
    //     imageUris?.let {
    //         // For simplicity, just display the first image and all URIs as text
    //         if (it.isNotEmpty()) {
    //             sharedImageView.setImageURI(it[0])
    //             sharedContentTextView.text = "Shared Multiple Images:\n" + it.joinToString("\n") { uri -> uri.toString() }
    //         }
    //     }
    //     intent.getStringExtra(Intent.EXTRA_SUBJECT)?.let { subject ->
    //         subjectTextView.text = "Subject:\n$subject"
    //     }
    // }
}

